            except TypeError:
                continue

    return count


def update_project_members(
    acting_user_id: int,
    project_identifier: int,
    modification: str,
    user_to_update_id: int
) -> bool:
    """
    Allow project owners to add/remove team members on their own projects;
    admins may manage any project.

    Args:
        acting_user_id: The user performing the modification.
        project_identifier: The project to modify.
        modification: 'add' or 'remove'.
        user_to_update_id: The user to add/remove.

    Returns:
        True if the modification is successful; otherwise False.
    """
    # Validate and normalize inputs
    try:
        aid = int(acting_user_id)
        pid = int(project_identifier)
        uid = int(user_to_update_id)
    except (TypeError, ValueError):
        return False

    mod = str(modification).strip().lower()
    if mod not in ("add", "remove"):
        return False

    # Access globals
    projects = globals().get("PROJECTS")
    users = globals().get("USERS")

    if not isinstance(projects, dict) or not isinstance(users, dict):
        return False

    project = projects.get(pid)
    if not isinstance(project, dict):
        return False

    # Validate actors and permissions
    if aid not in users or uid not in users:
        return False

    acting_user = users.get(aid)
    role = acting_user.get("role") if isinstance(acting_user, dict) else None
    owner_id = project.get("owner_id")

    # Permission: admin can manage any project; otherwise must be owner
    if role != "admin" and owner_id != aid:
        return False

    # Perform modification
    if mod == "add":
        if not add_user_to_project(uid, pid):
            return False
        members = projects.get(pid, {}).get("members")
        try:
            if isinstance(members, dict):
                return uid in members
            if isinstance(members, (set, list, tuple)):
                return uid in members
            return uid in members  # best-effort fallback
        except Exception:
            return False

    # mod == "remove"
    if not remove_user_from_project(uid, pid):
        return False
    members = projects.get(pid, {}).get("members")
    if members is None:
        return True
    try:
        if isinstance(members, dict):
            return uid not in members
        if isinstance(members, (set, list, tuple)):
            return uid not in members
        return uid not in members  # best-effort fallback
    except Exception:
        return False
